import React, { useState } from 'react';
import './ImportDataSidebar.css';

function ImportDataSidebar({ onSelectUserStory, onClose, isSidebarVisible, credentials }) {
  const [domain, setDomain] = useState(credentials?.domain || ''); // Use credentials passed from ChatBox
  const [project, setProject] = useState('');
  const [issueType, setIssueType] = useState('');
  const [jiraData, setJiraData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const fetchJiraData = async () => {
    setLoading(true);
    setError(null);

    try {
      const response = await fetch(
        `https://localhost:7216/api/UserStoryDescription/ExportAllUserStories?domain=${domain}&project=${project}&issueType=${issueType}`
      );

      if (!response.ok) {
        throw new Error('Failed to fetch Jira data.');
      }

      const data = await response.json();
      setJiraData(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleUserStoryClick = (story) => {
    onSelectUserStory(story);
  };

  const handleClearJiraData = () => {
    setJiraData([]);
  };

  return (
    <div className={`import-sidebar ${isSidebarVisible ? 'visible' : ''}`}>
      <button className="close-btn" onClick={onClose}>X</button>
      <div className="sidebar-title"><strong>Fetch Jira User Stories</strong></div>

      <div className="input-fields">
        <input
          type="text"
          placeholder="Domain"
          value={domain}
          onChange={(e) => setDomain(e.target.value)}
        />
        <input
          type="text"
          placeholder="Project"
          value={project}
          onChange={(e) => setProject(e.target.value)}
        />
        <input
          type="text"
          placeholder="Issue Type"
          value={issueType}
          onChange={(e) => setIssueType(e.target.value)}
        />
      </div>

      <button className="fetch-btn" onClick={fetchJiraData} disabled={loading}>
        {loading ? 'Loading...' : 'Fetch User Stories'}
      </button>

      {error && <div className="error-message">{error}</div>}

      <div className="jira-data">
        {jiraData.length > 0 && (
          <ul>
            {jiraData.map((story, index) => (
              <li key={index} onClick={() => handleUserStoryClick(story)}>
                {story.title}
              </li>
            ))}
          </ul>
        )}

        {jiraData.length === 0 && !loading && !error && (
          <p>No user stories found.</p>
        )}
      </div>

      {jiraData.length > 0 && (
        <button className="clear-btn" onClick={handleClearJiraData}>Clear</button>
      )}
    </div>
  );
}

export default ImportDataSidebar;
